const Q_CHEMISTRY_2017_MODEL_II=[{"id": "objective>Chemistry>2017-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds absorbs moisture from the atmosphere and dissolves in it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">KCl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (Iron(III) chloride) absorbs moisture from the atmosphere and dissolves in it. This property is known as deliquescence.  <br/> Deliquescent substances have the ability to attract and hold water molecules from the surrounding environment and form a solution. Other examples of deliquescent substances include NaOH, KOH, MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> etc</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2017-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanedioic acid is an organic solid that can be purified by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decancation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an effective method for purifying solids. In this process, the solid is dissolved in a suitable solvent to form a solution. As the solution cools, the pure solid crystallizes out, leaving impurities in the solution. Ethanedioic acid can be purified using this method by dissolving it in hot water and then allowing it to recrystallize upon cooling.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2017-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lowest level of molecular disorderliness is found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ice at -10°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water at 100°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steam at 100°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ice at 0°C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The level of molecular disorderliness is also known as entropy. Solids have the lowest entropy because their molecules are tightly packed and have less freedom to move around. Therefore, ice at -10°C, which is a solid state of water, has the lowest level of molecular disorderliness.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2017-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following mathematically expresses, the ideal gas equation </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P α nVT</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PT α nV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P α nT/V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PV α n/T</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ideal gas equation is PV=nRT, where P is the pressure, V is the volume, n is the number of moles, R is the gas constant, and T is the temperature. This equation can be rearranged to P=nRT/V, which is equivalent to P α nT/V.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2017-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases will have the lowest rate of diffusion under the same conditions? <br/> [N = 14, O = 16, Cl = 35.5, Ar = 40]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Argon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From Graham's Law of Diffusion, rate of diffusion is inversely proportional to the square root of the relative molecular mass. This implies that the higher the mass, the slower the rate of diffusion. <br/> Therefore, in the options given, the gas with the highest mass will have the lowest rate of diffusion. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">M&nbsp;</span></td></tr></table></div> <br/> Argon - 40gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Chlorine - 71gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Nitrogen - 28gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Oxygen - 32 gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2017-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about liquids is/are true? <br/> I.       Liquids maintain their volume at constant temperature. <br/> II.     Liquids have fixed shape <br/> III. Liquids do not diffuse <br/> IV.   Change in pressure affects volume of liquids</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A liquid is a nearly incompressible fluid that conforms to the shape of its container but retains a (nearly) constant volume independent of pressure</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2017-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the criteria for confirming the purity of benzene is to determine its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purity of a substance can be confirmed by determining its boiling point. Pure substances have a specific boiling point. If the boiling point of the substance matches the known boiling point of benzene, then it can be confirmed that the benzene is pure.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2017-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greenhouse effect is associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Particulate matter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heavy metals</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The greenhouse effect is primarily associated with Carbon (IV) oxide (also known as Carbon Dioxide). This is because Carbon Dioxide and other greenhouse gases like Methane, Nitrous Oxide, and Water Vapor trap heat from the sun in the Earth's atmosphere leading to a warming of the planet.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2017-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal rod burns less readily in air than the finely divided metal because the rod has </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different chemical properties </div>", "<div style=\"font-family:Cambria;font-size:17px;\">larger surface area exposed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protective oxide coating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smaller surface area exposed </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction varies directly to the surface area of solid reactant exposed. The rod form of a metal has smaller surface area exposed than the same mass of the finely divided form of the metals.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2017-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among these factors is responsible for an increase in the rate of a reaction on heating?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in enthalpy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing in collision rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in reactant concentration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On heating, the kinetic energies of the reactant particles increase thereby increasing collision rate to increase. So a higher fraction of the reactant particles have the necessary minimum energy to react. Hence reaction rate increases. <br/>  <br/> The \"on heating\" in the question should be taken noticed of. <br/>  <br/> On heating, the temperature is increased, this increases the average kinetic energy of the reactant particles which causes an increase in the collision rate which leads to an increase in the rate of reaction</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2017-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why are noble gases unreactive? This is because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">their outermost shells are partially filled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they have complete outer shells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the atomicity of their molecules </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are non-metals</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The noble gases (group 0 elements) have all the occupied orbitals in their outermost shells filled up with electrons. This accounts for their special stability and low reactivity.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2017-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Producer gas is a mixture of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> nd NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Producer gas is a mixture of Carbon Monoxide (CO) and Nitrogen (N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). It is produced by passing air over red-hot coke. The nitrogen in the air remains unchanged and dilutes the gas, reducing the temperature of combustion.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the partial pressure of oxygen at s.t.p. in a gaseous mixture containing 100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen and 900 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of nitrogen gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.9 atm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Partial pressure is found by Dalton's Law: <br/> Px = PTotal ( nx / nTotal ) <br/> where <br/> Px = partial pressure of gas x <br/> PTotal = total pressure of all gases <br/> nx = number of moles of gas x <br/> nTotal = number of moles of all gases <br/> Step 1 <br/> Find PTotal <br/> Standard pressure is 1 atm. <br/> Step 2 <br/> Add up the number of moles of the component gases to find nTotal <br/> nTotal = noxygen + nnitrogen <br/> nTotal = 100 + 900 <br/> nTotal =1000cm3 <br/> Step 3 <br/> Now you have all the information needed to plug the values into the equation and solve for Poxygen <br/> Poxygen = PTotal ( noxygen / nTotal ) <br/> Poxygen = 1 atm ( 100 / 1000 ) <br/> Poxygen= 0.1atm <br/> Answer <br/> The partial pressure of the oxygen is 0.1 atm.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2017-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the reactions of marble with dilute H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is fastest?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5g of marble lump at 50°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5g of marble lump at 25°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5g of marble powder at 50°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5g of marble powder at 25°C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of marble powder has a large surface area exposed to reaction than the same mass of lump. The reaction is more enhanced at 50°C than 25°C for the fact that a higher fraction of the reactant particles would reach the activation energy hence the reaction of marble powder at 50°C is the fastest.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2017-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following compounds will heat be absorbed on adding water? <br/> I. KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> II. Concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> III. NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat is absorbed (endothermic process) when water is added to both KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl. On the other hand, heat is released (exothermic process) when water is added to concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2017-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following letters in pairs denotes elements containing the same number of electrons in their outermost shells?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C and D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E and F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B and G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and B</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elements which belong to the same group contain the same number of electrons in their outermost shells.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2017-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents  positron</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>n</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>β</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>β</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A positron is a type of particle that is the antiparticle of the electron. It has the same mass as an electron but has a positive charge. It is represented as 0/1 β.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2017-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> In the reaction above, the standard heat of formation of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> are -277KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, -393KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and -286KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> respectively. The heat change of the reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-1921 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1921 KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1367 KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1367 KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ΔH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">F</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span> = ∑Hp - ∑Hr <br/> ΔH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = ((-393 × 2) + (-286 x 3)) - (-277 + 0) <br/> ΔH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = -786 - 858 + 277 <br/> ΔH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = -1,367KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Note that the heat of formation of an element is always 0</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2017-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transition metal is expected to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">form oxides with different formulas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have strong oxidizing ability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have low density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have an atomic structure with an incomplete outermost shell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transition metals are known for their ability to form a variety of different compounds, including oxides with different formulas. This is due to their unique electron configuration, which allows them to form multiple oxidation states.</div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2017-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions removes the major impurity in iron ore during the extraction of iron in the blast furnace?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 3CO → 2Fe + 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + CaO → CaSiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → CaO + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + C → 2CO</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earthly impurity, Silica (SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is the major impurity in iron ore. It is converted to slag in the blast furnace by reacting with Calcium oxide produced from the decomposition of limestone. SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + CaO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → CaSiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span></div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2017-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What process is illustrated below? <br/> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> ⇋ S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span> (in the presence of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Decomposition of a solid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Melting of a solid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of saturated solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation of a solid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process illustrated is the formation of a saturated solution. A saturated solution is a solution in which the maximum amount of solute has been dissolved in a solvent at a given temperature.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2017-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of copper would be deposited by passing 1 Faraday of electricity through a CuCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1 Faraday of electricity is equal to the charge of 1 mole of electrons, which is 96,485 coulombs. The reduction of copper(II) ions in solution to copper metal requires 2 electrons per ion, so 1 Faraday of electricity will deposit 0.5 moles of copper. <br/> 1 Faraday * (2 electrons/Cu ion) / (1 mole electrons/96,485 coulombs) * (1 mole Cu/2 electrons) = 0.5 moles Cu</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2017-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Oxidation number of iodine in the Iodate ion (lO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the iodate ion (IO3-), the oxidation number of iodine is +5. This is determined by the fact that oxygen has an oxidation number of -2, and there are three oxygen atoms for every iodine atom. The overall charge of the ion is -1, so the oxidation number of iodine must be +5 to balance out the -6 from the oxygen atoms.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2017-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The balanced ionic equation for the reaction between K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7(aq)</span> and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> in an acid medium is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 3SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 4Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 3SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3 SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The half equations are : <br/> Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 14H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 6e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> →  2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O (reduction half reaction) <br/> SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O →  SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> (oxidation half reaction) <br/> Multiple the reduction half reaction by 1 and the oxidation half reaction by 3 to balance the electrons  <br/> Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 14H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 6e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> →  2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O (reduction half reaction <br/> 3SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 6H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O →  3SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 12H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 6e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> (oxidation half reaction) <br/>  <br/> Next combine both half reaction to cancel out species that appear on both sides of the resulting equation and electrons. Hence <br/> Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 3SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3 SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2017-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction represented by the equation: <br/> Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2 (g)</span> → CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3 (s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. <br/> In the reaction above CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> acts as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An acidic oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A basic Oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A dehydrating</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of reaction <br/> Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> reacts with a base, Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to give a salt (CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) and water. <br/> Hence, it functions as an acidic oxide.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2017-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An atom <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>X decays by alpha particle emission to form an atom Y. The atomic number and Mass number of Y are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90 and 234</div>", "<div style=\"font-family:Cambria;font-size:17px;\">91 and 238</div>", "<div style=\"font-family:Cambria;font-size:17px;\">92 and 236</div>", "<div style=\"font-family:Cambria;font-size:17px;\">93 and 238 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the information given, we have: <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">90</span>Y <br/> The atomic number of Y = 90 and mass number = 234</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2017-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals in group 1 has the highest ionization energy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>Li</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">55</span>Cs</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">37</span>Rb</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ionization energy is the energy required to remove an electron from an atom. In the periodic table, ionization energy generally increases from left to right across a period and decreases down a group. Therefore, among the group 1 elements listed, lithium (Li) has the highest ionization energy.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2017-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the number of unpaired electrons in 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration 1s2 2s2 2p6 3s2 3p6 4s1 represents an atom in the ground state. In this configuration, the 4s orbital has one electron. Since each orbital can hold a maximum of two electrons, there is one unpaired electron in this atom.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2017-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of covalent bonds formed by nitrogen is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen has five electrons in its outer shell and needs three more to complete its octet. Therefore, it can form three covalent bonds by sharing three of its electrons with other atoms.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2017-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When candle wax is heated, it softens and then melts over a range of temperatures. This observation shows that was is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrocarbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lubricant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Candle wax is made from a heavy petroleum fraction which consists of a mixture of hydrocarbons. Hence, it melts over a range of temperature. It is only a pure substance than can melt at a definite temperature.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2017-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Filtration method is used to separate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">immiscible liquids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">insoluble solid from liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">miscible liquids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soluble solid from a solution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Filtration method is used to separate insoluble solid from liquid. Filtration is a separation method used to separate out pure substances in mixtures comprised of particles, some of which are large enough in size to be captured with a porous material.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2017-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrocarbon containing 18.2% Hydrogen has a vapour density of 22. Its molecular formula is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrocarbons are organic compounds that consist of Carbon and Hydrogen only <br/> % composition of Hydrogen  = 18.2%  <br/> % composition of Carbon = 100 - 18.2 = 81.8% <br/>  C=81.8/12,H=18.2/1( Divide by their RAM) <br/>  <br/> C=6.82/6.82, H=18.2/6.82(Divide by the smallest) <br/>  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2.67</span>(multiply by 3 to get whole number) <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span> <br/> Empirical formula = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span> <br/> Molecular mass  = (EF)n <br/> since Molecular mass = 2 x V.D <br/> and V.D = 22 <br/> m.m = 2 × 22 <br/> m.m = 44 <br/> 44 = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>)n <br/> 44 = (36 + 8)n <br/> 44 = 44n <br/> n = 1  <br/> (molecular formula = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>)</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2017-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the percentage by mass of oxygen in calcium trioxocarbonate (IV). <br/> [Ca = 40, O = 16, C = 12]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">48</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">RMM of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = (1 × RAM of Ca) + (1 × RAM of C) + (3 × RAM of O) <br/> = (1 × 40) + (1 × 12) + (3 × 16) <br/> = 40 + 12 + 48 <br/> = 100 <br/> % by mass of\toxygen <br/> =no of atoms of oxygen × RAM of oxygen/RMM of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> × 100 <br/> = (3 × 16)/10× 100 <br/> = 48/100 ×100= 48%</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2017-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vapour density of an Organic Compound is 27. If its empirical formula is C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, the compound is an </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aromatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m.m = E.F × n <br/> and m.m = 2 × V.D = 2 × 27 = 54 <br/> 54 = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)n <br/> 54 = 24n + 3n <br/> 54 = 27n <br/> n = 2 <br/> Hence, the molecular formula of the compound is C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> <br/> This formular conforms to the general molecular formular of Alkyne C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n-2</span> hence the organic compound is an Alkyne</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2017-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the diagram below: <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The set up of is used for the preparation of a salt by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">double decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystalization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct combination</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the reaction involves an acid and a base, it is a neutralization reaction.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2017-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the function of calcium hydroxide in the treatment of municipal water supply</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">killing bacteria in the water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the water hardness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coagulating solid particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling the pH of the water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium hydroxide is used for controlling the pH of the water</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2017-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of molten Lead bromide using Carbon electrodes ,</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine gas is given off at anode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bromine gas is given off at cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon electrodes dissolve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroxide ion is discharges at anode</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the cathode <br/> Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Pb<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> {reduction} <br/> At the anode <br/> 2Br<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> {Oxidation} <br/> From the equation of the anode, it can be inferred that bromine gas is given off at the anode.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2017-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electrolysis is applied in the following processes except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electroplating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Extracting of Aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Extracting of Iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Purification of Copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrolysis is not applied in the extraction of iron. Electrolysis is a very expensive process, and hence is only used for very reactive metals such as Aluminium and Copper.</div>", "topic": "ELECTROLYSIS : USES OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2017-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the amount of copper (in moles) that will be deposited by passing 3 Faradays of electricity through a solution of copper (II) salt.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction at the cathode <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> From the cathodic reaction above, <br/> 2F of electricity will give 1 mole of Cu <br/> 3F of electricity will give x Cu <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />x</td></tr></table></div> <br/> 2x = 3 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">Cu</td></tr></table></div></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2017-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conductivity of an electrolyte increase as its concentration</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is unaffected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces to Zero</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conductivity of an electrolyte increases as its concentration increases. This is because the number of ions that carry the current in the solution increases with the concentration of the electrolyte. Therefore, the more concentrated the electrolyte, the higher its conductivity.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}];
